class User {
    var name: String = ""
    var email: String = ""
    var age: Int = 0

    override fun toString() = "User(name='$name', email='$email', age=$age)"
}

fun main() {
    // apply: configure
    val user = User().apply {
        name = "Alice"
        email = "alice@test.com"
        age = 30
    }

    // let: transform
    val greeting = user.name?.let { "Hello, $it!" } ?: "Hello!"
    println(greeting)

    // also: side effect
    val logged = user.also {
        println("Created user: $it")
    }

    // run: compute
    val info = user.run {
        "$name ($age) - $email"
    }
    println(info)
}
